class Solution {
public:
    long long findMaximumNumber(long long k, int x) {
        long long num = 0, total = 0;
        while (true) {
            long long price = 0, temp = num;
            while (temp) {
                if (temp & (1 << (x - 1))) price++;
                temp >>= x;
            }
            if (total + price > k) break;
            total += price;
            num++;
        }
        return num - 1;
    }
};
```
